import axios from "axios";
import React, { useEffect, useState } from "react";
import { Link } from "react-router-dom";
import Swal from "sweetalert2";

function ViewCategory()
{

    const [loading, setLoading] = useState(true);
     const [categoryList, setCategoryList] = useState([]);

    useEffect(() => {
        let isMounted = true;

        // This is the corrected API endpoint to match your api.php file.
        axios.get('/api/categories').then(res => 
        {
            if (isMounted) 
            {
                if (res.status === 200) 
                {
                    setCategoryList(res.data.category);
                }
                setLoading(false);
            }
            }).catch(error => 
            {
                if (isMounted) 
                {
                    setLoading(false);
                    console.error("Error fetching categories:", error);
                    // Now, if a 404 or other error occurs, the user gets a clear message.
                    Swal.fire({
                                title: 'Error!',
                                text: 'Could not fetch categories. Please check the API endpoint and network connection.',
                                icon: 'error',
                                confirmButtonText: 'OK'
                    });
                }
            });
}, []);

var ViewCategory_HTMLTABLE = "";
if(loading)
{
    return <h4>Loading Category...</h4>
}
else
{
    ViewCategory_HTMLTABLE =
    categorylist.map( (item) =>
    {
        return(
            <tr>
                <td>{item.id}</td>
                <td>{item.name}</td>
                <td>{item.slug}</td>
                <td>{item.status}</td>
                <td>
                    <Link to={`edit-category/${item.id}`} className="btn btn-primary btn-sm">Edit</Link>
                </td>
                <td>
                    <button type="button" className="btn btn-danger btn-sm">Delete</button>
                </td>
            </tr>
        )
    });
}

    return(
        <div className="container px-4">
            <div className="card">
                <div className="card-header">
                    <h4>Category List
                        <Link to= "/admin/add-category" className="btn btn-primary btn-sm float-end"> Add Category</Link>
                    </h4>
                </div>
                <div className="card-body">
                    <table className="table table-bordered table-striped">
                        <thead>
                            <tr>
                                <th>ID</th>
                                <th>Name</th>
                                <th>Slug</th>
                                <th>Status</th>
                                <th>Edit</th>
                                <th>Delete</th>
                            </tr>
                        </thead>
                        <tbody>
                            {ViewCategory_HTMLTABLE}
                        </tbody>
                    </table>
                </div>
            </div>
        </div>
    )
}
export default ViewCategory;
